118	#[tauri::command]
119	fn toggle_finding(index: usize, window: tauri::WebviewWindow) -> Result<(), String> {
120	    {
121	        let mut states = ZAPCAP_TOGGLE_STATES.lock()
122	            .map_err(|e| format!("lock error: {}", e))?;
123	        if index < states.len() {
124	            states[index] = if states[index] == "elide" {
125	                "pass".to_string()
126	            } else {
127	                "elide".to_string()
128	            };
129	        }
130	    }
131	    zapcap_push_triage(&window)
132	}
