134	#[tauri::command]
135	fn copy_anonymized(window: tauri::WebviewWindow) -> Result<(), String> {
136	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
137	        .map_err(|e| format!("lock error: {}", e))?
138	        .clone();
139	
140	    let anonymized = {
141	        let cache = ZAPCAP_LAST_CLINICAL.lock()
142	            .map_err(|e| format!("lock error: {}", e))?;
143	        let clinical = cache.as_ref()
144	            .ok_or_else(|| "no clinical data to anonymize".to_string())?;
145	        apcd::apcre_engine::apcre_anonymize(
146	            &clinical.plain_text,
147	            &clinical.findings,
148	            &toggle_states,
149	        )
150	    };
151	
152	    let mut clipboard = arboard::Clipboard::new()
153	        .map_err(|e| format!("clipboard error: {}", e))?;
154	    clipboard.set_text(anonymized)
155	        .map_err(|e| format!("clipboard error: {}", e))?;
156	
157	    zapcap_push_triage_with_feedback(&window, "Copied!")?;
158	
159	    let win = window.clone();
160	    std::thread::spawn(move || {
161	        std::thread::sleep(std::time::Duration::from_secs(2));
162	        let _ = zapcap_push_triage(&win);
163	    });
164	
165	    Ok(())
166	}
