181	fn zapcap_push_triage_with_feedback(
182	    window: &tauri::WebviewWindow,
183	    btn_text: &str,
184	) -> Result<(), String> {
185	    // Clone data out of locks to avoid holding multiple locks simultaneously
186	    let (findings, plain_text) = {
187	        let cache = ZAPCAP_LAST_CLINICAL.lock()
188	            .map_err(|e| format!("lock error: {}", e))?;
189	        let clinical = cache.as_ref()
190	            .ok_or_else(|| "no clinical data for triage".to_string())?;
191	        (clinical.findings.clone(), clinical.plain_text.clone())
192	    };
193	    let toggle_states = ZAPCAP_TOGGLE_STATES.lock()
194	        .map_err(|e| format!("lock error: {}", e))?
195	        .clone();
