250	// ---------------------------------------------------------------------------
251	// HTML rendering — document preview with inline PHI highlights
252	// ---------------------------------------------------------------------------
253	
254	fn zapcap_render_preview(
255	    findings: &[apcrm_Finding],
256	    plain_text: &str,
257	    toggle_states: &[String],
258	) -> String {
259	    // Build index-annotated list sorted by offset (byte offsets used directly)
260	    let mut sorted: Vec<(usize, &apcrm_Finding)> = findings.iter().enumerate().collect();
261	    sorted.sort_by(|a, b| a.1.offset.cmp(&b.1.offset).then(b.1.length.cmp(&a.1.length)));
262	
263	    let mut parts = Vec::new();
264	    let mut pos: usize = 0;
265	
266	    for (idx, f) in &sorted {
267	        if f.offset < pos { continue; } // skip overlap
268	
269	        // Text before this finding
270	        if f.offset > pos {
271	            parts.push(zapcap_escape_html(&plain_text[pos..f.offset]));
272	        }
273	
274	        // Finding span — byte offsets consumed directly, no conversion needed
275	        let end = f.offset + f.length;
276	        let cls = if toggle_states.get(*idx).map(|s| s.as_str()) == Some("pass") {
277	            "phi-pass"
278	        } else if f.severity == apcrm_Severity::Red {
279	            "phi-red"
280	        } else {
281	            "phi-yellow"
282	        };
283	
284	        parts.push(format!(
285	            "<span class=\"{}\" data-index=\"{}\">{}</span>",
286	            cls, idx, zapcap_escape_html(&plain_text[f.offset..end])
287	        ));
288	        pos = end;
289	    }
290	
291	    // Remaining text
292	    if pos < plain_text.len() {
293	        parts.push(zapcap_escape_html(&plain_text[pos..]));
294	    }
295	
296	    parts.join("")
297	}
