299	// ---------------------------------------------------------------------------
300	// HTML rendering — findings panel (yellow + red sections)
301	// ---------------------------------------------------------------------------
302	
303	fn zapcap_render_findings(
304	    findings: &[apcrm_Finding],
305	    toggle_states: &[String],
306	) -> (String, String) {
307	    let mut yellow = Vec::new();
308	    let mut red = Vec::new();
309	
310	    for (i, f) in findings.iter().enumerate() {
311	        let state = toggle_states.get(i).map(|s| s.as_str()).unwrap_or("elide");
312	        let label = zapcap_format_category(f.category);
313	        let btn_text = if state == "elide" { "ELIDE \u{25bc}" } else { "PASS \u{25bc}" };
314	
315	        let entry = format!(
316	            "<div class=\"finding-entry\">\
317	             <span class=\"finding-text\">{}</span>\
318	             <span class=\"finding-category\">{}</span>\
319	             <button class=\"finding-toggle {}\" \
320	             onclick=\"window.__TAURI__.core.invoke('toggle_finding',{{index:{}}})\"\
321	             >{}</button></div>",
322	            zapcap_escape_html(&f.text),
323	            label,
324	            state,
325	            i,
326	            btn_text
327	        );
328	
329	        if f.severity == apcrm_Severity::Yellow {
330	            yellow.push(entry);
331	        } else {
332	            red.push(entry);
333	        }
334	    }
335	
336	    let yellow_html = if yellow.is_empty() {
337	        "<div class=\"empty-section\">None detected</div>".to_string()
338	    } else {
339	        yellow.join("")
340	    };
341	
342	    let red_html = if red.is_empty() {
343	        "<div class=\"empty-section\">None detected</div>".to_string()
344	    } else {
345	        red.join("")
346	    };
347	
348	    (yellow_html, red_html)
349	}
