351	// ---------------------------------------------------------------------------
352	// Utilities
353	// ---------------------------------------------------------------------------
354	
355	fn zapcap_format_category(cat: apcrm_PhiCategory) -> &'static str {
356	    match cat {
357	        apcrm_PhiCategory::Name         => "NAME",
358	        apcrm_PhiCategory::Provider     => "PROVIDER",
359	        apcrm_PhiCategory::Facility     => "FACILITY",
360	        apcrm_PhiCategory::Date         => "DATE",
361	        apcrm_PhiCategory::Dob          => "DOB",
362	        apcrm_PhiCategory::Phone        => "PHONE",
363	        apcrm_PhiCategory::Email        => "EMAIL",
364	        apcrm_PhiCategory::Ssn          => "SSN",
365	        apcrm_PhiCategory::Mrn          => "MRN",
366	        apcrm_PhiCategory::Account      => "ACCOUNT",
367	        apcrm_PhiCategory::EncounterId  => "ENCOUNTER ID",
368	        apcrm_PhiCategory::Address      => "ADDRESS",
369	        apcrm_PhiCategory::HealthPlanId => "HEALTH PLAN ID",
370	        apcrm_PhiCategory::DeviceId     => "DEVICE ID",
371	        apcrm_PhiCategory::Npi          => "NPI",
372	        apcrm_PhiCategory::Dea          => "DEA",
373	        apcrm_PhiCategory::Url          => "URL",
374	        apcrm_PhiCategory::IpAddress    => "IP ADDRESS",
375	    }
376	}
377	
378	fn zapcap_escape_html(text: &str) -> String {
379	    text.replace('&', "&amp;")
380	        .replace('<', "&lt;")
381	        .replace('>', "&gt;")
382	        .replace('"', "&quot;")
383	}
384	
385	fn zapcap_js_string_literal(s: &str) -> String {
386	    let mut out = String::with_capacity(s.len() + 2);
387	    out.push('"');
388	    for c in s.chars() {
389	        match c {
390	            '\\'     => out.push_str("\\\\"),
391	            '"'      => out.push_str("\\\""),
392	            '\n'     => out.push_str("\\n"),
393	            '\r'     => out.push_str("\\r"),
394	            '\t'     => out.push_str("\\t"),
395	            '\u{08}' => out.push_str("\\b"),
396	            '\u{0C}' => out.push_str("\\f"),
397	            '\u{2028}' => out.push_str("\\u2028"),
398	            '\u{2029}' => out.push_str("\\u2029"),
399	            c if (c as u32) < 0x20 => out.push_str(&format!("\\u{:04x}", c as u32)),
400	            c => out.push(c),
401	        }
402	    }
403	    out.push('"');
404	    out
405	}
406	
407	// ---------------------------------------------------------------------------
408	// Entry point
409	// ---------------------------------------------------------------------------
410	
411	fn main() {
412	    apcd::apcrl_info_now!("starting Ann's PHI Clipbuddy");
413	    apcd::apcru_update::apcru_start_watcher();
414	    tauri::Builder::default()
415	        .invoke_handler(tauri::generate_handler![toggle_finding, copy_anonymized])
416	        .setup(|app| {
417	            use tauri::Manager;
418	            let window = app.get_webview_window("main")
419	                .expect("main window must exist");
420	            let win = window.clone();
421	            window.on_window_event(move |event| {
422	                if let tauri::WindowEvent::Focused(true) = event {
423	                    if let Err(e) = zapcap_handle_focus(&win) {
424	                        apcd::apcrl_error_now!("focus handler error: {}", e);
425	                    }
426	                }
427	            });
428	            Ok(())
429	        })
430	        .run(tauri::generate_context!())
431	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("tauri application error: {}", e));
432	}
